// ===== STAGE 0: Parse + enrich form data =====
const f = $input.first().json;
const g = (k) => (f[k] || '').trim();

// Generate a unique campaign ID for tracking
const campaignId = 'CMP-' + Date.now().toString(36).toUpperCase() + '-' + Math.random().toString(36).substring(2, 6).toUpperCase();

// Build UTM-tagged URLs for every channel
const baseUrl = g('Brand Website') || 'https://example.com';
const utm = (source, medium, campaign) => baseUrl + (baseUrl.includes('?') ? '&' : '?') + 'utm_source=' + source + '&utm_medium=' + medium + '&utm_campaign=' + encodeURIComponent(campaign) + '&utm_id=' + campaignId;

// Parse competitors into array
const competitorsArr = g('Competitor Brands').split(',').map(c => c.trim()).filter(Boolean);

// Map budget to recommended channel mix
const budget = g('Marketing Budget (Monthly)');
let channelMix = {};
if (budget.includes('Bootstrap')) channelMix = { organic_social: 60, influencer: 20, whatsapp: 15, paid_ads: 5 };
else if (budget.includes('Lean')) channelMix = { paid_ads: 40, organic_social: 30, influencer: 20, email_whatsapp: 10 };
else if (budget.includes('Growth')) channelMix = { paid_ads: 50, influencer: 20, content: 15, email_whatsapp: 10, pr: 5 };
else channelMix = { paid_ads: 45, influencer: 20, tv_ott: 15, content: 10, pr_events: 10 };

return [{ json: {
  campaignId,
  productName: g('Product Name'),
  category: g('Product Category'),
  productDesc: g('Product Description & Key Ingredients/Features'),
  price: g('Price (MRP)'),
  launchOffer: g('Launch Offer / Discount'),
  targetAudience: g('Target Audience'),
  usps: g('Unique Selling Points (USPs)'),
  competitors: g('Competitor Brands'),
  competitorsArr,
  availableOn: g('Available On'),
  brandName: g('Brand Name'),
  brandWebsite: baseUrl,
  brandVoice: g('Brand Voice & Tone'),
  visualAesthetic: g('Visual Aesthetic Direction'),
  brandColor: g('Primary Brand Color (HEX)') || '#2563EB',
  languages: g('Languages to Generate'),
  ownerName: g('Brand Owner Name'),
  ownerEmail: g('Brand Owner Email'),
  ownerWhatsapp: g('Brand Owner WhatsApp (with country code)'),
  launchDate: g('Launch Date') || 'Already live',
  budget,
  channelMix,
  agentName: g('Your Name (Agency)'),
  agencyName: g('Agency Name'),
  agentEmail: g('Your Email'),
  timestamp: new Date().toISOString(),
  dateGenerated: new Date().toLocaleDateString('en-IN', { year:'numeric', month:'long', day:'numeric' }),
  utm_links: {
    facebook_ad: utm('facebook', 'cpc', 'launch_' + campaignId),
    google_ad: utm('google', 'cpc', 'launch_' + campaignId),
    instagram_organic: utm('instagram', 'social', 'launch_' + campaignId),
    email_launch: utm('email', 'newsletter', 'launch_' + campaignId),
    whatsapp: utm('whatsapp', 'broadcast', 'launch_' + campaignId),
    influencer: utm('influencer', 'referral', 'launch_' + campaignId),
    youtube: utm('youtube', 'video', 'launch_' + campaignId),
    linkedin: utm('linkedin', 'social', 'launch_' + campaignId)
  }
}}];

// Parse market intel — skip thinking parts, try each part as JSON
const aiResp = $input.first().json;
const prod = $('🔧 Parse + Enrich + Campaign ID + UTM').first().json;
let intel = {};
let parsed = false;

const parts = aiResp?.candidates?.[0]?.content?.parts || [];

// Try each non-thinking part individually
for (const p of parts) {
  if (parsed) break;
  if (p.thought) continue; // skip thinking blocks
  const t = (p.text || '').trim();
  if (!t) continue;

  // Try direct parse
  try { intel = JSON.parse(t); parsed = true; continue; } catch(e) {}
  // Try strip markdown fences
  try { const f = t.replace(/^[\s\S]*?```(?:json)?\s*\n?/i, '').replace(/\n?\s*```[\s\S]*$/, '').trim(); intel = JSON.parse(f); parsed = true; continue; } catch(e) {}
  // Try extract { to }
  try { const fb = t.indexOf('{'); const lb = t.lastIndexOf('}'); if (fb !== -1 && lb > fb) { intel = JSON.parse(t.substring(fb, lb + 1)); parsed = true; continue; } } catch(e) {}
  // Try fix trailing commas
  try { const fb = t.indexOf('{'); const lb = t.lastIndexOf('}'); if (fb !== -1 && lb > fb) { intel = JSON.parse(t.substring(fb, lb + 1).replace(/,\s*([}\]])/g, '$1')); parsed = true; } } catch(e) {}
}

// Last resort: concatenate all non-thinking parts and try
if (!parsed) {
  const allText = parts.filter(p => !p.thought).map(p => p.text || '').join('\n');
  try { const fb = allText.indexOf('{'); const lb = allText.lastIndexOf('}'); if (fb !== -1 && lb > fb) { intel = JSON.parse(allText.substring(fb, lb + 1).replace(/,\s*([}\]])/g, '$1')); parsed = true; } } catch(e) {}
}

if (!parsed) {
  intel = {
    market_size_inr_cr: 'Analysis pending',
    positioning_statement: prod.productName + ' for ' + prod.targetAudience.substring(0,50),
    competitor_analysis: [],
    market_gaps: prod.usps.split(',').slice(0,3),
    swot: { strengths:[], weaknesses:[], opportunities:[], threats:[] },
    differentiation_hooks: [], category_trends_2026: [], recommended_launch_channels: [],
    projected_metrics: { month_1_revenue_estimate_inr: 'TBD', target_cac: 'TBD', target_aov: prod.price, target_roas: '3:1' }
  };
}
return [{ json: { ...prod, intel, _intelParsed: parsed, _partsCount: parts.length } }];

