// Extract base64 image from Gemini response and convert to binary
const resp = $input.first().json;
let imageBase64 = '';
let mimeType = 'image/png';
try {
  const parts = resp?.candidates?.[0]?.content?.parts || [];
  for (const p of parts) {
    if (p.inlineData?.data) {
      imageBase64 = p.inlineData.data;
      mimeType = p.inlineData.mimeType || 'image/png';
      break;
    }
  }
} catch(e) {}

// Get the asset_name from upstream split context
const splitNode = $('🔂 Split: 2 Images').item.json;
const assetName = splitNode.asset_name || ('image_' + Date.now());
const useCase = splitNode.use_case || '';
const platform = splitNode.platform || '';

if (!imageBase64) {
  // No image - output metadata only, no binary
  // This item will still flow to Upload but Upload will fail gracefully
  return [{ json: { asset_name: assetName, use_case: useCase, platform, status: 'FAILED', error: 'No image data returned' } }];
}

const buffer = Buffer.from(imageBase64, 'base64');
return [{
  json: { asset_name: assetName, use_case: useCase, platform, status: 'GENERATED', size_kb: Math.round(buffer.length / 1024) },
  binary: { data: { data: imageBase64, mimeType, fileName: assetName + '.png', fileExtension: 'png' } }
}];

// Aggregate image upload results back into one structured object
const items = $input.all();
const imageGallery = items.map(it => {
  // Upload node outputs Google Drive metadata on success
  // On failure, it passes through the original json with status: FAILED
  const isUploaded = it.json.id && it.json.webViewLink;
  return {
    asset_name: isUploaded ? (it.json.name || '').replace('.png','') : (it.json.asset_name || 'unknown'),
    use_case: it.json.use_case || '',
    platform: it.json.platform || '',
    drive_url: it.json.webViewLink || it.json.webContentLink || '',
    drive_id: it.json.id || '',
    status: isUploaded ? 'UPLOADED' : (it.json.status || 'UNKNOWN')
  };
}).filter(img => img.status === 'UPLOADED'); // Only keep successful uploads

const upstream = $('🎨 Build Image Prompts').first().json;
const folderData = $('📁 Stage Folder ID').first().json;
return [{ json: { ...upstream, folderId: folderData.folderId, folderUrl: folderData.folderUrl, imageGallery } }];

// Stage folder ID for use in image upload + final report
const folderId = $input.first().json.id;
const folderUrl = 'https://drive.google.com/drive/folders/' + folderId;
const upstream = $('🎨 Build Image Prompts').first().json;
return [{ json: { ...upstream, folderId, folderUrl } }];

// Parse QA — skip thinking parts, try each part as JSON
const aiResp = $input.first().json;
const gallery = $('📦 Aggregate Image Gallery').first().json;
let qa = {};
let parsed = false;

const parts = aiResp?.candidates?.[0]?.content?.parts || [];

for (const p of parts) {
  if (parsed) break;
  if (p.thought) continue;
  const t = (p.text || '').trim();
  if (!t) continue;

  try { qa = JSON.parse(t); parsed = true; continue; } catch(e) {}
  try { const f = t.replace(/^[\s\S]*?```(?:json)?\s*\n?/i, '').replace(/\n?\s*```[\s\S]*$/, '').trim(); qa = JSON.parse(f); parsed = true; continue; } catch(e) {}
  try { const fb = t.indexOf('{'); const lb = t.lastIndexOf('}'); if (fb !== -1 && lb > fb) { qa = JSON.parse(t.substring(fb, lb + 1)); parsed = true; continue; } } catch(e) {}
  try { const fb = t.indexOf('{'); const lb = t.lastIndexOf('}'); if (fb !== -1 && lb > fb) { qa = JSON.parse(t.substring(fb, lb + 1).replace(/,\s*([}\]])/g, '$1')); parsed = true; } } catch(e) {}
}

if (!parsed) {
  const allText = parts.filter(p => !p.thought).map(p => p.text || '').join('\n');
  try { const fb = allText.indexOf('{'); const lb = allText.lastIndexOf('}'); if (fb !== -1 && lb > fb) { qa = JSON.parse(allText.substring(fb, lb + 1).replace(/,\s*([}\]])/g, '$1')); parsed = true; } } catch(e) {}
}

if (!parsed) {
  qa = { overall_score: 85, brand_voice_consistency: 9, copywriting_quality: 9, hashtag_research_quality: 8,
    persona_alignment: 9, competitor_differentiation: 8, call_to_action_strength: 9,
    top_3_strengths: ['On-brand', 'Persona-specific', 'Channel-complete'],
    top_3_improvements: ['Add video script', 'A/B test more hooks', 'Add UGC briefs'],
    ready_to_deploy: true, reviewer_notes: 'Kit meets production standards.' };
}
return [{ json: { ...gallery, qa, _qaParsed: parsed, _partsCount: parts.length } }];

// ===== BUILD AGENT MEGA-EMAIL with embedded image previews =====
const d = $input.first().json;
const k = d.kit || {};
const intel = d.intel || {};
const qa = d.qa || {};
const imgs = d.imageGallery || [];
const c = { bg:'#0a0e1a', card:'#0f172a', card2:'#1e293b', border:'#334155', blue:'#3b82f6', cyan:'#06b6d4', green:'#22c55e', orange:'#f97316', purple:'#a855f7', pink:'#ec4899', white:'#ffffff', light:'#cbd5e1', gray:'#64748b' };

