'<p style="margin:8px 0 0;color:#e0e7ff;font-size:14px;">' + d.productName + ' \u2022 ' + d.brandName + ' \u2022 ' + d.price + '</p>' +
'<div style="display:inline-block;margin-top:10px;padding:6px 14px;background:rgba(255,255,255,0.18);border-radius:14px;color:#fff;font-size:11px;font-weight:700;">QA Score: ' + (qa.overall_score || 'N/A') + '/100 \u2022 ' + (qa.ready_to_deploy ? '\u2705 READY TO DEPLOY' : '\u23F3 NEEDS REVIEW') + '</div>' +
'</div>' +
'<div style="background:' + c.card2 + ';padding:20px;border-radius:0 0 12px 12px;border:1px solid ' + c.border + ';border-top:none;">' +

// Executive Summary
section('\u{1F4CC} Executive Summary', c.blue, box(k.launch_brief_summary)) +

// Market Intel
section('\u{1F9E0} Market Intelligence', c.cyan,
  sub('Positioning Statement') + box(intel.positioning_statement) +
  sub('Market Size (India TAM)') + box(intel.market_size_inr_cr) +
  sub('Top Competitor Weaknesses to Exploit') + box((intel.competitor_analysis || []).map(ca => '\u2022 ' + ca.name + ': ' + ca.weaknesses).join('\n')) +
  sub('Market Gaps') + box((intel.market_gaps || []).map(m => '\u2022 ' + m).join('\n')) +
